  private static readonly SHIFT = 5; // log2(32)
  private static readonly MASK = 0x1F; // 32 - 1

  private readonly nodes: Array<Array<T | null>>;
  private readonly depth: number;
  private readonly size: number;

  private constructor(nodes: Array<Array<T | null>>, depth: number, size: number) {
    this.nodes = nodes;
    this.depth = depth;
    this.size = size;
  }

  static empty<T>(): PersistentVector<T> {
    return new PersistentVector<T>([], 0, 0);
  }

  get size(): number {
    return this.size;
  }

  get(i: number): T {
    if (i < 0 || i >= this.size) {
      throw new RangeError(`Index ${i} out of bounds for vector of size ${this.size}`);
    }
    return this._get(i, 0);
  }

  push(value: T): PersistentVector<T> {
    if (this.size === 0) {
      // Create a new root with one leaf
      const leaf: Array<T | null> = new Array(PersistentVector.BRANCH_FACTOR).fill(null);
      leaf[0] = value;
      return new PersistentVector<T>([leaf], 0, 1);
    }

    // Determine if we need to increase depth
    const newDepth = this._newDepthRequired();
    let newNodes: Array<Array<T | null>>;

    if (newDepth > this.depth) {
      // Need to create a new root level
      const oldRoot = this.nodes[0];
      const newRoot: Array<Array<T | null> | T | null> = new Array(PersistentVector.BRANCH_FACTOR).fill(null);
      newRoot[0] = oldRoot;
      newRoot[1] = this._pushTail(oldRoot, value, 0);
      newNodes = [newRoot as Array<Array<T | null> | T | null>];
    } else {
      // Same depth, just update the path
      newNodes = this._updatePath(value, 0);
    }

    return new PersistentVector<T>(newNodes, newDepth, this.size + 1);
  }

  private _newDepthRequired(): number {
    // Calculate the number of bits needed to represent the new size
    const newSize = this.size + 1;
    if (newSize <= PersistentVector.BRANCH_FACTOR) {
      return 0;
    }
    const bits = Math.ceil(Math.log2(newSize) / PersistentVector.SHIFT);
    return bits;
  }

  private _get(i: number, level: number): T {
    if (level === this.depth) {
      // Leaf level
      const leaf = this.nodes[level];
      const idx = i & PersistentVector.MASK;
      const val = leaf[idx];
      if (val === null) {
        throw new Error("Internal error: null value in leaf");
      }
      return val as T;
    }

    const node = this.nodes[level];
    const idx = (i >> (level * PersistentVector.SHIFT)) & PersistentVector.MASK;
    const child = node[idx];

    if (child === null) {
      throw new Error("Internal error: null child");
    }

    // If child is a leaf array, we're at the next level
