type ParseQuery<S extends string> = S extends ''
  ? {}
  : S extends `${infer Key}=${infer Rest}`
    ? Rest extends `${infer Value}&${infer Next}`
      ? { [K in Key]: Value } & ParseQuery<Next>
      : { [K in Key]: Rest }
    : S extends `${infer Key}&${infer Rest}`
      ? ParseQuery<Rest>
      : {}

export class EventEmitter<TEvents extends Record<string, unknown[]>> {
  private listeners: Map<keyof TEvents, Array<(...args: any) => void>> = new Map();

  on<K extends keyof TEvents>(name: K, handler: (...args: TEvents[K]) => void): void {
    const existing = this.listeners.get(name);
    if (existing) {
      existing.push(handler as (...args: any) => void);
    } else {
      this.listeners.set(name, [handler as (...args: any) => void]);
    }
  }

  emit<K extends keyof TEvents>(name: K, ...args: TEvents[K]): void {
    const handlers = this.listeners.get(name);
    if (handlers) {
      for (const handler of handlers) {
        handler(...args);
      }
    }
  }
}

